class Solution:
    def smallestNumber(self, n):
        bits = n.bit_length()
        x = (1 << bits) - 1
        if x < n:
            x = (1 << (bits + 1)) - 1
        return x

solutions.python:
class Solution:
    def smallestNumber(self, n):
        x = 1
        while x < n:
            x = x * 2 + 1
        return x

